import sys
import os
import json
import csv
import io

def load_csv(path):
    with open(path, 'r', newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        rows = list(reader)
    return rows

def load_json(path):
    with open(path, 'r', encoding='utf-8') as f:
        data = json.load(f)
    if isinstance(data, list):
        return data
    elif isinstance(data, dict):
        # If it's a dict of lists (columnar), convert to row-oriented
        keys = list(data.keys())
        if keys and isinstance(data[keys[0]], list):
            length = len(data[keys[0]])
            return [{k: data[k][i] if i < len(data[k]) else None for k in keys} for i in range(length)]
        return [data]
    return []

def load_yaml(path):
    try:
        import yaml
        with open(path, 'r', encoding='utf-8') as f:
            data = yaml.safe_load(f)
        if isinstance(data, list):
            return data
        elif isinstance(data, dict):
            return [data]
        return []
    except ImportError:
        raise ImportError('PyYAML is required for YAML input. Install with: pip install pyyaml')

def detect_format(path):
    ext = os.path.splitext(path)[1].lower()
    if ext in ('.csv', '.tsv'):
        return 'csv'
    elif ext in ('.json', '.jsonl'):
        return 'json'
    elif ext in ('.yaml', '.yml'):
        return 'yaml'
    # Sniff content
    with open(path, 'r', encoding='utf-8') as f:
        start = f.read(100).strip()
    if start.startswith(('{', '[')):
        return 'json'
    if ':' in start and not ',' in start.split('\n')[0]:
        return 'yaml'
    return 'csv'

def write_csv(rows, path):
    if not rows:
        with open(path, 'w') as f:
            f.write('')
        return
    fieldnames = list(rows[0].keys())
    with open(path, 'w', newline='', encoding='utf-8') as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(rows)

def write_json(rows, path):
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(rows, f, indent=2, default=str)

def write_yaml(rows, path):
    try:
        import yaml
        with open(path, 'w', encoding='utf-8') as f:
            yaml.dump(rows, f, default_flow_style=False, allow_unicode=True)
    except ImportError:
        # Fallback: manual YAML-like output
        with open(path, 'w', encoding='utf-8') as f:
            for i, row in enumerate(rows):
                f.write(f'- # item {i}\n')
                for k, v in row.items():
                    val = json.dumps(v) if isinstance(v, (dict, list)) else str(v) if v is not None else 'null'
                    f.write(f'  {k}: {val}\n')

def write_markdown(rows, path):
    if not rows:
        with open(path, 'w') as f:
            f.write('(empty)\n')
        return
    headers = list(rows[0].keys())
    with open(path, 'w', encoding='utf-8') as f:
        f.write('| ' + ' | '.join(headers) + ' |\n')
        f.write('| ' + ' | '.join(['---'] * len(headers)) + ' |\n')
        for row in rows:
            vals = [str(row.get(h, '')).replace('|', '\\|').replace('\n', ' ') for h in headers]
            f.write('| ' + ' | '.join(vals) + ' |\n')

def main():
    inputs = json.loads(os.environ.get('SKILL_INPUTS', '{}'))
    input_path = inputs.get('inputPath', '')
    output_format = inputs.get('outputFormat', 'json')

    if not input_path or not os.path.exists(input_path):
        print(json.dumps({'outputPath': '', 'rowCount': 0, 'error': f'File not found: {input_path}'}))
        return

    # Detect and load
    src_format = detect_format(input_path)
    loaders = {'csv': load_csv, 'json': load_json, 'yaml': load_yaml}
    try:
        rows = loaders[src_format](input_path)
    except Exception as e:
        print(json.dumps({'outputPath': '', 'rowCount': 0, 'error': f'Failed to load {src_format}: {e}'}))
        return

    # Build output path
    base = os.path.splitext(input_path)[0]
    ext_map = {'json': '.json', 'csv': '.csv', 'yaml': '.yaml', 'markdown': '.md'}
    output_path = base + ext_map.get(output_format, '.out')
    # Avoid overwriting input
    if os.path.abspath(output_path) == os.path.abspath(input_path):
        output_path = base + '_converted' + ext_map.get(output_format, '.out')

    # Write
    writers = {'csv': write_csv, 'json': write_json, 'yaml': write_yaml, 'markdown': write_markdown}
    try:
        writers[output_format](rows, output_path)
    except Exception as e:
        print(json.dumps({'outputPath': '', 'rowCount': len(rows), 'error': f'Failed to write {output_format}: {e}'}))
        return

    print(json.dumps({'outputPath': output_path, 'rowCount': len(rows)}))

if __name__ == '__main__':
    main()
